sql:
SELECT player_id, game_id, goals, assists 
FROM player_game_stats
WHERE goals > 4 AND assists > 2;

SELECT season_id, team_id, points, points_percentage 
FROM team_season_stats 
WHERE points_percentage > 0.5;

SELECT team_id, SUM(games_played) AS Total_Games_Played
FROM team_season_stats
GROUP BY team_id;

SELECT SUM(points) AS total_points
FROM team_season_stats
WHERE season_id = 1 AND team_id = 1;

SELECT player_name, position
FROM players
WHERE player_id = (
  SELECT player_id
  FROM player_game_stats
  WHERE goals = (
    SELECT MAX(goals)
    FROM player_game_stats
  )
);
